  ('diplomatic-a3078d07-moex-00060', 'diplomatic-a3078d07', 'diplomatic-a3078d07-moex-114-c655adf3', 'sub-diplomatic-a3078d07-04', NULL, 'single_choice', '依司法院釋字第 689 號解釋，判斷立法者制定之法定程序，是否符合憲法上正當法律程序原則之要 求，應考量之因素不包括下列何者？', '["人民權利受侵害或限制時，應有使其獲得救濟之機會與制度", "所涉基本權之種類、限制之強度及範圍、所欲追求之公共利益、決定機關之功能合適性", "有無替代程序或各項可能程序成本", "法律安定性"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:29+00:00", "source_pdf_sha1": "74e57a3571a6", "answer_pdf_sha1": "b3f1a7073313", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-印尼文組"}'::jsonb, NULL),
  ('diplomatic-a3078d07-moex-00061', 'diplomatic-a3078d07', 'diplomatic-a3078d07-moex-114-c655adf3', 'sub-diplomatic-a3078d07-04', NULL, 'single_choice', '依原住民身分法規定，下列各選項中之丙，何者原本無法取得原住民身分，然已被憲法法庭判決宣告 該規定違憲？', '["原住民甲與原住民乙結婚所生，從乙之姓氏之女丙", "原住民甲與非原住民乙結婚所生，從甲之姓氏之子丙", "原住民甲與非原住民乙結婚所生，從乙之姓氏之女丙", "原住民甲與非原住民乙結婚所生，從具原住民傳統名字之女丙"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:29+00:00", "source_pdf_sha1": "74e57a3571a6", "answer_pdf_sha1": "b3f1a7073313", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-印尼文組"}'::jsonb, NULL),
  ('diplomatic-a3078d07-moex-00062', 'diplomatic-a3078d07', 'diplomatic-a3078d07-moex-114-c655adf3', 'sub-diplomatic-a3078d07-04', NULL, 'single_choice', '有關基本國策，下列敘述何者錯誤？', '["憲法基本國策有屬指導國家政策及整體國家發展之方針者", "「國家為謀社會福利，應實施社會保險制度」，此為我國基本國策之一", "「國家為增進民族健康，應普遍推行衛生保健事業及公醫制度」，此為我國基本國策之一", "基本國策中所指之「國家」，均指中央，不包括地方自治團體"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:29+00:00", "source_pdf_sha1": "74e57a3571a6", "answer_pdf_sha1": "b3f1a7073313", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-印尼文組"}'::jsonb, NULL),
  ('diplomatic-a3078d07-moex-00063', 'diplomatic-a3078d07', 'diplomatic-a3078d07-moex-114-c655adf3', 'sub-diplomatic-a3078d07-04', NULL, 'single_choice', '依司法院大法官解釋意旨，關於性言論，下列敘述何者錯誤？', '["立法機關為維持社會風化，得以法律限制性言論", "具藝術性、醫學性或教育性之性言論，須採取適當安全隔絕措施，方受憲法保障", "含有性暴力、性虐待或人獸性交且不具藝術性、醫學性或教育性價值之言論，不受憲法保障", "性交易言論若非以兒少為對象或促使兒少為性交易，且訊息之接收人僅限成年人，亦屬憲法所保障 之商業性言論"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:29+00:00", "source_pdf_sha1": "74e57a3571a6", "answer_pdf_sha1": "b3f1a7073313", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-印尼文組"}'::jsonb, NULL),
  ('diplomatic-a3078d07-moex-00064', 'diplomatic-a3078d07', 'diplomatic-a3078d07-moex-114-c655adf3', 'sub-diplomatic-a3078d07-04', NULL, 'single_choice', '有關人民團體法與結社自由，下列敘述何者錯誤？', '["基於結社自由，人民團體得自主選擇其名稱", "對於人民結社所為之各項限制，以設立管制最為嚴重，應受比例原則之嚴格審查", "為確保自由民主憲政秩序，主管機關對主張共產主義或分裂國土之人民團體得直接不予許可設立", "政黨之解散，由主管機關檢同相關事證移送司法院大法官組成憲法法庭審理之"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:29+00:00", "source_pdf_sha1": "74e57a3571a6", "answer_pdf_sha1": "b3f1a7073313", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-印尼文組"}'::jsonb, NULL),
